// A more advanced audio processor to create a robust voiceprint.
// This implementation uses Mel-Frequency Cepstral Coefficients (MFCCs)
// and their derivatives (Deltas and Delta-Deltas) for detailed feature extraction.
// ENHANCEMENTS: Pre-emphasis, Voice Activity Detection, Cepstral Liftering, and Spectral Flattening.

// Custom error for specific voice processing issues.
export class VoiceProcessingError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'VoiceProcessingError';
  }
}

const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();

// --- MFCC Configuration ---
const NUM_MFCC_COEFFICIENTS = 13; 
const FFT_SIZE = 1024; 
const NUM_MEL_FILTERS = 40; 
const PRE_EMPHASIS_ALPHA = 0.97; 
const CEPSTRAL_LIFTER_PARAM = 22; 

// --- Voice Activity Detection (VAD) Configuration ---
const VAD_ENERGY_THRESHOLD_HIGH = 0.02;   // Increased to be more selective
const VAD_ENERGY_THRESHOLD_LOW = 0.005;   // Increased to avoid noise
const VAD_ZCR_THRESHOLD = 0.08;           // Increased for better speech distinction
const VAD_SFM_THRESHOLD = 0.08;            // Tighter spectral flatness check

// --- Security Thresholds ---
// 0.992 is very strict for cosine similarity. 
// For production biometric systems, this would usually be calibrated via FAR/FRR testing.
export const SIMILARITY_THRESHOLD = 0.992;
const MIN_REQUIRED_SPEECH_FRAMES = 50; // Ensure at least ~0.5s of speech was actually analyzed

// --- DSP & Math Helper Functions ---

const applyHammingWindow = (frame: Float32Array): void => {
    const N = frame.length;
    for (let i = 0; i < N; i++) {
        frame[i] *= 0.54 - 0.46 * Math.cos(2 * Math.PI * i / (N - 1));
    }
};

const fft = (input: Float32Array): { real: Float32Array; imag: Float32Array } => {
    const n = input.length;
    if ((n & (n - 1)) !== 0) return { real: new Float32Array(n), imag: new Float32Array(n) };
    const log2n = Math.log2(n);
    const real = new Float32Array(n);
    const imag = new Float32Array(n);
    for (let i = 0; i < n; i++) {
        let rev = 0;
        for (let j = 0; j < log2n; j++) {
            if ((i >> j) & 1) rev |= 1 << (log2n - 1 - j);
        }
        real[rev] = input[i];
    }
    for (let size = 2; size <= n; size *= 2) {
        const halfSize = size / 2;
        const angleStep = -2 * Math.PI / size;
        for (let i = 0; i < n; i += size) {
            for (let j = 0; j < halfSize; j++) {
                const angle = j * angleStep;
                const w_real = Math.cos(angle);
                const w_imag = Math.sin(angle);
                const k = i + j;
                const l = k + halfSize;
                const t_real = real[l] * w_real - imag[l] * w_imag;
                const t_imag = real[l] * w_imag + imag[l] * w_real;
                real[l] = real[k] - t_real;
                imag[l] = imag[k] - t_imag;
                real[k] += t_real;
                imag[k] += t_imag;
            }
        }
    }
    return { real, imag };
}

const hzToMel = (hz: number): number => 2595 * Math.log10(1 + hz / 700);
const melToHz = (mel: number): number => 700 * (Math.pow(10, mel / 2595) - 1);

const createMelFilterbank = (fftSize: number, numFilters: number, sampleRate: number): number[][] => {
  const fMax = sampleRate / 2;
  const melMax = hzToMel(fMax);
  const melMin = hzToMel(0);
  const melPoints = new Float32Array(numFilters + 2);
  for (let i = 0; i < melPoints.length; i++) {
    melPoints[i] = melMin + i * (melMax - melMin) / (numFilters + 1);
  }
  const hzPoints = melPoints.map(mel => melToHz(mel));
  const binPoints = hzPoints.map(hz => Math.floor((fftSize + 1) * hz / sampleRate));
  const filterbank: number[][] = [];
  for (let i = 0; i < numFilters; i++) {
    const filter = new Array(Math.floor(fftSize / 2) + 1).fill(0);
    const startBin = binPoints[i];
    const centerBin = binPoints[i + 1];
    const endBin = binPoints[i + 2];
    for (let j = startBin; j < centerBin; j++) filter[j] = (j - startBin) / (centerBin - startBin);
    for (let j = centerBin; j < endBin; j++) filter[j] = (endBin - j) / (endBin - centerBin);
    filterbank.push(filter);
  }
  return filterbank;
};

const dct = (input: Float32Array, numCoefficients: number): Float32Array => {
    const N = input.length;
    const output = new Float32Array(numCoefficients);
    const c0 = Math.sqrt(1 / N);
    const c = Math.sqrt(2 / N);
    for (let k = 0; k < numCoefficients; k++) {
      let sum = 0;
      for (let n = 0; n < N; n++) sum += input[n] * Math.cos(Math.PI * k * (2 * n + 1) / (2 * N));
      output[k] = k === 0 ? c0 * sum : c * sum;
    }
    return output;
};

const computeDeltas = (features: Float32Array[], N: number = 2): Float32Array[] => {
    const numFrames = features.length;
    if (numFrames === 0) return [];
    const numCoeffs = features[0].length;
    const deltas: Float32Array[] = [];
    let denominator = 0;
    for (let i = 1; i <= N; i++) denominator += i * i;
    denominator *= 2;
    for (let t = 0; t < numFrames; t++) {
        const deltaFrame = new Float32Array(numCoeffs);
        for (let i = 0; i < numCoeffs; i++) {
            let numerator = 0;
            for (let n = 1; n <= N; n++) {
                const futureIndex = Math.min(numFrames - 1, t + n);
                const pastIndex = Math.max(0, t - n);
                numerator += n * (features[futureIndex][i] - features[pastIndex][i]);
            }
            deltaFrame[i] = numerator / denominator;
        }
        deltas.push(deltaFrame);
    }
    return deltas;
}

const calculateSpectralFlatness = (powerSpectrum: Float32Array): number => {
    const K = powerSpectrum.length;
    if (K === 0) return 0;
    let geometricMean = 0;
    let arithmeticMean = 0;
    const epsilon = 1e-10;
    for (let i = 0; i < K; i++) {
        geometricMean += Math.log(powerSpectrum[i] + epsilon);
        arithmeticMean += powerSpectrum[i];
    }
    geometricMean = Math.exp(geometricMean / K);
    arithmeticMean /= K;
    return arithmeticMean === 0 ? 0 : geometricMean / arithmeticMean;
};

export const generateVoiceprint = async (audioBlob: Blob): Promise<Float32Array> => {
  const arrayBuffer = await audioBlob.arrayBuffer();
  const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);
  const pcmData = audioBuffer.getChannelData(0);

  const emphasizedPcm = new Float32Array(pcmData.length);
  emphasizedPcm[0] = pcmData[0];
  for (let i = 1; i < pcmData.length; i++) {
    emphasizedPcm[i] = pcmData[i] - PRE_EMPHASIS_ALPHA * pcmData[i - 1];
  }

  const melFilterbank = createMelFilterbank(FFT_SIZE, NUM_MEL_FILTERS, audioBuffer.sampleRate);
  const allMfccs: Float32Array[] = [];
  const hopLength = Math.round(audioBuffer.sampleRate * 0.010); 

  for (let i = 0; i + FFT_SIZE <= emphasizedPcm.length; i += hopLength) {
      const frame = emphasizedPcm.slice(i, i + FFT_SIZE);
      let rmsEnergy = 0;
      for (const sample of frame) rmsEnergy += sample * sample;
      rmsEnergy = Math.sqrt(rmsEnergy / frame.length);

      let zcr = 0;
      for (let j = 1; j < frame.length; j++) {
        if ((frame[j] >= 0 && frame[j-1] < 0) || (frame[j] < 0 && frame[j-1] >= 0)) zcr++;
      }
      zcr /= frame.length;

      applyHammingWindow(frame);
      const { real, imag } = fft(frame);
      const powerSpectrum = new Float32Array(FFT_SIZE / 2 + 1);
      for (let k = 0; k < powerSpectrum.length; k++) powerSpectrum[k] = (real[k] * real[k] + imag[k] * imag[k]) / FFT_SIZE;

      const spectralFlatness = calculateSpectralFlatness(powerSpectrum);
      const isSpeech = 
          rmsEnergy > VAD_ENERGY_THRESHOLD_HIGH || 
          (rmsEnergy > VAD_ENERGY_THRESHOLD_LOW && zcr > VAD_ZCR_THRESHOLD && spectralFlatness < VAD_SFM_THRESHOLD);

      if (!isSpeech) continue;

      const melEnergies = new Float32Array(NUM_MEL_FILTERS).fill(0);
      for (let j = 0; j < NUM_MEL_FILTERS; j++) {
          for (let k = 0; k < powerSpectrum.length; k++) melEnergies[j] += melFilterbank[j][k] * powerSpectrum[k];
      }

      const logMelEnergies = melEnergies.map(e => Math.log(e > 0 ? e : 1e-6));
      const mfccs = dct(logMelEnergies, NUM_MFCC_COEFFICIENTS);
      const lifter = new Float32Array(NUM_MFCC_COEFFICIENTS);
      for(let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) {
        lifter[j] = 1.0 + (CEPSTRAL_LIFTER_PARAM / 2.0) * Math.sin(Math.PI * (j + 1) / CEPSTRAL_LIFTER_PARAM);
        mfccs[j] *= lifter[j];
      }
      allMfccs.push(mfccs);
  }

  if (allMfccs.length < MIN_REQUIRED_SPEECH_FRAMES) {
      throw new VoiceProcessingError("Insufficient speech data detected. Please speak clearly for the full duration.");
  }

  const deltaMfccs = computeDeltas(allMfccs);
  const deltaDeltaMfccs = computeDeltas(deltaMfccs);

  const voiceprintLength = NUM_MFCC_COEFFICIENTS * 3;
  const voiceprint = new Float32Array(voiceprintLength).fill(0);

  for (let i = 0; i < allMfccs.length; i++) {
      for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) {
          voiceprint[j] += allMfccs[i][j];
          voiceprint[j + NUM_MFCC_COEFFICIENTS] += deltaMfccs[i][j];
          voiceprint[j + NUM_MFCC_COEFFICIENTS * 2] += deltaDeltaMfccs[i][j];
      }
  }

  for (let i = 0; i < voiceprintLength; i++) voiceprint[i] /= allMfccs.length;

  const magnitude = Math.sqrt(voiceprint.reduce((sum, val) => sum + val * val, 0));
  if (magnitude > 0) {
      for (let i = 0; i < voiceprint.length; i++) voiceprint[i] /= magnitude;
  }
  return voiceprint;
};

/**
 * Calculates the similarity score between two voiceprints.
 */
export const getVoiceSimilarityScore = (vp1: Float32Array, vp2: Float32Array): number => {
  if (vp1.length !== vp2.length) return 0;
  let dotProduct = 0;
  for (let i = 0; i < vp1.length; i++) dotProduct += vp1[i] * vp2[i];
  return dotProduct;
};

export const compareVoiceprints = (vp1: Float32Array | null, vp2: Float32Array | null): boolean => {
  if (!vp1 || !vp2) return false;
  const score = getVoiceSimilarityScore(vp1, vp2);
  console.log(`Voiceprint Match Score: ${score.toFixed(4)} (Threshold: ${SIMILARITY_THRESHOLD})`);
  return score > SIMILARITY_THRESHOLD;
};

import React, { useState, useEffect, useRef } from 'react';
import { AuthAction, User } from '../types';
import { MicIcon } from './icons/MicIcon';
import { XMarkIcon } from './icons/XMarkIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { generateVoiceprint, compareVoiceprints, getVoiceSimilarityScore, SIMILARITY_THRESHOLD, VoiceProcessingError } from '../utils/audioProcessor';

interface AuthModalProps {
  action: AuthAction;
  onClose: () => void;
  onSuccess: (result?: any) => void;
  onFailure: (reason: string) => void;
}

const RECORDING_DURATION_MS = 5000; 

const AuthModal: React.FC<AuthModalProps> = ({ action, onClose, onSuccess, onFailure }) => {
  const [status, setStatus] = useState<'idle' | 'recording' | 'processing' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [countdown, setCountdown] = useState(RECORDING_DURATION_MS / 1000);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number | null>(null);
  const countdownIntervalRef = useRef<number | null>(null);

  const title = action.type === 'enroll' ? 'Voice Enrollment' : 'Voice Verification';
  const instruction = action.type === 'enroll'
    ? `To create your voiceprint, click the microphone and say "Secure my data with the sound of my voice"`
    : `To confirm your identity, click the microphone and say "Secure my data with the sound of my voice"`;

  const clearTimers = () => {
    if (recordingTimerRef.current) clearTimeout(recordingTimerRef.current);
    if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
  };

  const startRecording = async () => {
    if (status !== 'idle') return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: { sampleRate: 44100, channelCount: 1, echoCancellation: true }
      });
      mediaRecorderRef.current = new MediaRecorder(stream);
      audioChunksRef.current = [];

      mediaRecorderRef.current.ondataavailable = (event) => audioChunksRef.current.push(event.data);
      mediaRecorderRef.current.onstop = async () => {
        setStatus('processing');
        stream.getTracks().forEach(track => track.stop());

        if (audioChunksRef.current.length === 0) {
          setErrorMessage("No audio was recorded. Please try again.");
          setStatus('error');
          return;
        }

        try {
          const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
          const currentVoiceprint = await generateVoiceprint(audioBlob);

          if (action.type === 'enroll') {
            onSuccess(currentVoiceprint);
          } else if (action.type === 'verify') {
            if (!action.user.voiceprint) {
              onFailure("User has no enrolled voiceprint.");
              return;
            }
            if (compareVoiceprints(currentVoiceprint, action.user.voiceprint)) {
              onSuccess();
            } else {
              onFailure("Voice does not match. Please speak clearly and at a consistent pace.");
            }
          } else if (action.type === 'identify') {
            // BEST MATCH LOGIC: Check all users and find the highest similarity
            let bestMatchUser: User | null = null;
            let highestScore = -1;

            for (const user of action.users) {
                if (user.voiceprint) {
                    const score = getVoiceSimilarityScore(currentVoiceprint, user.voiceprint);
                    if (score > highestScore) {
                        highestScore = score;
                        bestMatchUser = user;
                    }
                }
            }

            // Only accept if the BEST match actually exceeds the security threshold
            if (bestMatchUser && highestScore > SIMILARITY_THRESHOLD) {
                console.log(`Identified as ${bestMatchUser.name} with confidence ${highestScore.toFixed(4)}`);
                onSuccess({ user: bestMatchUser, voiceprint: currentVoiceprint });
            } else {
                console.log(`Identity check failed. Highest similarity was ${highestScore.toFixed(4)}`);
                onFailure("Voice not recognized. Only enrolled users can access these files.");
            }
          }
        } catch (procError) {
          console.error("Voice processing error:", procError);
          onFailure(procError instanceof VoiceProcessingError ? procError.message : "Audio processing failed.");
        }
      };

      mediaRecorderRef.current.start();
      setStatus('recording');
      setCountdown(RECORDING_DURATION_MS / 1000);
      countdownIntervalRef.current = window.setInterval(() => setCountdown(prev => (prev > 1 ? prev - 1 : 0)), 1000);
      recordingTimerRef.current = window.setTimeout(() => stopRecording(), RECORDING_DURATION_MS);
    } catch (err) {
      setErrorMessage("Could not access microphone.");
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') mediaRecorderRef.current.stop();
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      if (mediaRecorderRef.current?.stream) mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    };
  }, []);

  const renderStatus = () => {
    switch (status) {
        case 'recording':
            return (
                <div className="text-center">
                    <div className="animate-pulse text-red-400 font-semibold">Recording...</div>
                    <p className="text-sm text-gray-400 mt-1">Automatically stops in {countdown}s</p>
                </div>
            );
        case 'processing':
             return (
                <div className="text-center flex flex-col items-center">
                    <SparklesIcon className="h-8 w-8 text-blue-400 animate-pulse mb-2" />
                    <div className="text-blue-300 font-semibold">Verifying Biometric ID...</div>
                    <p className="text-sm text-gray-400 mt-1">Matching against secure vault.</p>
                </div>
            );
        case 'error':
            return (
                <div className="text-center">
                    <div className="text-red-400 font-semibold">Security Error</div>
                    <p className="text-sm text-red-300 mt-1">{errorMessage}</p>
                </div>
            );
        default:
            return (
                 <div className="text-center">
                    <div className="font-semibold text-white">{title}</div>
                    <p className="text-sm text-gray-400 mt-1">{instruction}</p>
                </div>
            );
    }
  };

  return (
    <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-gray-800 rounded-2xl shadow-2xl w-full max-w-md p-8 border border-gray-700 relative">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-500 hover:text-white transition-colors">
            <XMarkIcon className="h-6 w-6" />
        </button>
        <div className="space-y-6">
            <div className="h-16 flex items-center justify-center">{renderStatus()}</div>
            <div className="flex justify-center">
                 <button 
                    onClick={startRecording}
                    disabled={status !== 'idle'}
                    className={`
                        w-24 h-24 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg
                        focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-blue-400
                        ${status === 'idle' ? 'bg-blue-600 hover:bg-blue-500 shadow-blue-500/50' : 'cursor-not-allowed'}
                        ${status === 'recording' ? 'bg-red-500 shadow-red-500/50 scale-110' : ''}
                        ${(status === 'processing' || status === 'error') ? 'bg-gray-600' : ''}
                    `}
                >
                    <MicIcon className="h-10 w-10 text-white" />
                </button>
            </div>
             {status === 'error' && (
                <button onClick={() => setStatus('idle')} className="w-full text-center text-blue-400 hover:text-blue-300 text-sm">
                    Try Again
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

export default AuthModal;

import { EncryptedFile, User } from "../types";

const APP_SECRET = "system-master-vault-secret-2025";
const SYSTEM_SALT = new TextEncoder().encode("voice-auth-system-fixed-salt-v1");

// Robust helper to convert ArrayBuffer to Base64 in chunks to avoid stack overflow on large files (15MB+)
const bufferToBase64 = (buffer: ArrayBuffer): string => {
  const bytes = new Uint8Array(buffer);
  let binary = '';
  const len = bytes.byteLength;
  const chunk_size = 0x8000; // 32KB chunks
  for (let i = 0; i < len; i += chunk_size) {
    binary += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk_size) as any);
  }
  return btoa(binary);
};

// Helper to convert Base64 to ArrayBuffer
const base64ToBuffer = (base64: string): ArrayBuffer => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
};

/**
 * Derives the System Key Encryption Key.
 * In this "System-Wide" model, we use a fixed salt so that any user 
 * authorized by the biometric gatekeeper can unlock the file.
 */
const deriveSystemKek = async (): Promise<CryptoKey> => {
  const encoder = new TextEncoder();
  const keyMaterial = await window.crypto.subtle.importKey(
    "raw",
    encoder.encode(APP_SECRET),
    { name: "PBKDF2" },
    false,
    ["deriveKey"]
  );

  return window.crypto.subtle.deriveKey(
    {
      name: "PBKDF2",
      salt: SYSTEM_SALT,
      iterations: 100000,
      hash: "SHA-256",
    },
    keyMaterial,
    { name: "AES-GCM", length: 256 },
    true,
    ["wrapKey", "unwrapKey"]
  );
};

// Encrypts a file using a System KEK
export const encryptFile = async (file: File): Promise<EncryptedFile> => {
  // 1. Generate a random File Encryption Key (FEK)
  const fek = await window.crypto.subtle.generateKey(
    { name: "AES-GCM", length: 256 },
    true,
    ["encrypt", "decrypt"]
  );

  // 2. Encrypt file content
  const iv = window.crypto.getRandomValues(new Uint8Array(12));
  const fileBuffer = await file.arrayBuffer();
  const ciphertextBuffer = await window.crypto.subtle.encrypt(
    { name: "AES-GCM", iv: iv },
    fek,
    fileBuffer
  );

  // 3. Wrap the FEK with the System KEK
  const systemKek = await deriveSystemKek();
  const wrappedKeyBuffer = await window.crypto.subtle.wrapKey(
    "raw",
    fek,
    systemKek,
    { name: "AES-GCM", iv: iv }
  );

  return {
    iv: bufferToBase64(iv),
    ciphertext: bufferToBase64(ciphertextBuffer),
    // We store a single wrapped key for the entire system
    wrappedKeys: [{
      userId: 0, // 0 indicates System-wide key
      wrappedKey: bufferToBase64(wrappedKeyBuffer),
    }],
    mimeType: file.type || 'application/octet-stream',
    originalFileName: file.name,
  };
};

// Decrypts a file after the user has been successfully identified by voice
export const decryptFile = async (
  encryptedData: EncryptedFile
): Promise<{ blob: Blob; fileName: string }> => {
    if (!encryptedData || !encryptedData.wrappedKeys?.[0]) {
        throw new Error("File is corrupted or not a valid encrypted file format.");
    }

    const systemKek = await deriveSystemKek();
    const iv = base64ToBuffer(encryptedData.iv);
    const wrappedKey = base64ToBuffer(encryptedData.wrappedKeys[0].wrappedKey);

    try {
      // 1. Unwrap the FEK using the System KEK
      const fek = await window.crypto.subtle.unwrapKey(
          "raw",
          wrappedKey,
          systemKek,
          { name: "AES-GCM", iv: iv },
          { name: "AES-GCM", length: 256 },
          true,
          ["decrypt"]
      );

      // 2. Decrypt main ciphertext
      const ciphertext = base64ToBuffer(encryptedData.ciphertext);
      const decryptedBuffer = await window.crypto.subtle.decrypt(
          { name: "AES-GCM", iv: iv },
          fek,
          ciphertext
      );

      return { 
        blob: new Blob([decryptedBuffer], { type: encryptedData.mimeType }), 
        fileName: encryptedData.originalFileName 
      };
    } catch (error) {
        console.error("Decryption crypto error:", error);
        throw new Error("Integrity check failed. The file could not be decrypted.");
    }
};

import React, { useState, useRef, useEffect } from 'react';
import { User, FileHistoryEntry } from '../types';
import AuthModal from './AuthModal';
import { encryptFile } from '../utils/crypto';
import { ArrowUpTrayIcon } from './icons/ArrowUpTrayIcon';
import { XMarkIcon } from './icons/XMarkIcon';

type Step = 'uploadFile' | 'verifyAndEncrypt' | 'download';

const MAX_FILE_SIZE_MB = 15;
const MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024;

interface EncryptionFlowProps {
  users: User[];
  onComplete: () => void;
  addLog: (text: string, type: 'info' | 'success' | 'error') => void;
  addFileHistoryEntry: (entry: Omit<FileHistoryEntry, 'id' | 'timestamp'>) => void;
}

const EncryptionFlow: React.FC<EncryptionFlowProps> = ({ users, onComplete, addLog, addFileHistoryEntry }) => {
  const [step, setStep] = useState<Step>('uploadFile');
  const [fileToEncrypt, setFileToEncrypt] = useState<File | null>(null);
  const [encryptedFileUrl, setEncryptedFileUrl] = useState<string | null>(null);
  const [encryptedFileName, setEncryptedFileName] = useState('');
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => {
      if (encryptedFileUrl) {
        URL.revokeObjectURL(encryptedFileUrl);
      }
    };
  }, [encryptedFileUrl]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE_BYTES) {
