        return;
      }
      setFileToEncrypt(file);
    }
  };

  const handleUploadSubmit = () => {
    if (fileToEncrypt) {
      setStep('verifyAndEncrypt');
      setIsAuthModalOpen(true);
      addLog(`File '${fileToEncrypt.name}' selected. Verifying system access via voice...`, 'info');
