type Step = 'uploadFile' | 'decryptVoice' | 'download';

const MAX_FILE_SIZE_MB = 15;
const MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024;

interface DecryptionFlowProps {
  users: User[];
  onComplete: () => void;
  addLog: (text: string, type: 'info' | 'success' | 'error') => void;
  addFileHistoryEntry: (entry: Omit<FileHistoryEntry, 'id' | 'timestamp'>) => void;
}

const DecryptionFlow: React.FC<DecryptionFlowProps> = ({ users, onComplete, addLog, addFileHistoryEntry }) => {
  const [step, setStep] = useState<Step>('uploadFile');
  const [encryptedFile, setEncryptedFile] = useState<File | null>(null);
  const [originalFileName, setOriginalFileName] = useState('');
  const [decryptedFileUrl, setDecryptedFileUrl] = useState<string | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [parsedEncryptedData, setParsedEncryptedData] = useState<EncryptedFile | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => {
      if (decryptedFileUrl) {
        URL.revokeObjectURL(decryptedFileUrl);
      }
    };
  }, [decryptedFileUrl]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
