      addLog(`Biometric identification successful: Welcome ${matchedUser.name}. Unlocking system vault...`, 'success');

      try {
        // System-wide decryption: No longer depends on when the user joined
        const { blob: decryptedBlob, fileName: originalName } = await decryptFile(parsedEncryptedData);

        setDecryptedFileUrl(URL.createObjectURL(decryptedBlob));
        setOriginalFileName(originalName);
        setStep('download');
        addLog(`File '${originalName}' decrypted successfully.`, 'success');
        addFileHistoryEntry({
          action: 'decrypted',
          originalFileName: originalName,
          userName: matchedUser.name,
          status: 'success',
