        setErrorMessage("Failed to access microphone. Please try again.");
      }
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
    }
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      if (mediaRecorderRef.current?.stream) {
        mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const renderStatus = () => {
    switch (status) {
        case 'recording':
            return (
                <div className="text-center">
                    <div className="animate-pulse text-red-400 font-semibold">Recording...</div>
                    <p className="text-sm text-gray-400 mt-1">Automatically stops in {countdown}s</p>
