import React, { useState, useCallback, useEffect, useRef } from 'react';
import Header from './components/Header';
import UserPanel from './components/UserPanel';
import SystemLog from './components/SystemLog';
import FileActions from './components/FileActions';
import EnrollmentFlow from './components/EnrollmentFlow';
import DecryptionFlow from './components/DecryptionFlow';
import EncryptionFlow from './components/EncryptionFlow';
import FileHistoryPanel from './components/FileHistoryPanel';
import { User, LogMessage, FileHistoryEntry } from './types';

type Flow = 'enroll' | 'encrypt' | 'decrypt' | null;
const MAX_USERS = 5;

const App: React.FC = () => {
  const [isLoaded, setIsLoaded] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [fileHistory, setFileHistory] = useState<FileHistoryEntry[]>([]);
  const [logMessages, setLogMessages] = useState<LogMessage[]>([]);
  const [currentFlow, setCurrentFlow] = useState<Flow>(null);

  // Initial load from localStorage
  useEffect(() => {
    try {
      const savedUsers = localStorage.getItem('voiceAuthUsers');
      if (savedUsers) {
        const parsed = JSON.parse(savedUsers);
        const hydratedUsers = parsed.map((user: any) => ({
          ...user,
          voiceprint: user.voiceprint ? new Float32Array(user.voiceprint) : null,
        }));
        setUsers(hydratedUsers);
        console.log("Loaded users from storage:", hydratedUsers.length);
      }

      const savedHistory = localStorage.getItem('voiceAuthFileHistory');
      if (savedHistory) {
        setFileHistory(JSON.parse(savedHistory));
      }

      addLog('System initialized. Security modules online.', 'info');
    } catch (error) {
      console.error("Failed to load data from localStorage", error);
      addLog('Warning: Could not restore previous session data.', 'error');
    } finally {
      setIsLoaded(true);
    }
  }, []);

  // Save users whenever they change, but only after initial load
  useEffect(() => {
    if (!isLoaded) return;

    try {
      const serializableUsers = users.map(user => ({
        ...user,
        voiceprint: user.voiceprint ? Array.from(user.voiceprint) : null,
      }));
      localStorage.setItem('voiceAuthUsers', JSON.stringify(serializableUsers));
    } catch (error) {
       console.error("Failed to save users to localStorage", error);
       if (error instanceof DOMException && error.name === 'QuotaExceededError') {
         addLog('Storage full. Could not save user profile.', 'error');
       }
    }
  }, [users, isLoaded]);

  // Save history whenever it changes, but only after initial load
  useEffect(() => {
    if (!isLoaded) return;

    try {
      localStorage.setItem('voiceAuthFileHistory', JSON.stringify(fileHistory));
    } catch (error) {
      console.error("Failed to save file history to localStorage", error);
    }
  }, [fileHistory, isLoaded]);

  const addLog = useCallback((text: string, type: LogMessage['type']) => {
    const timestamp = new Date().toLocaleTimeString();
    setLogMessages(prev => [...prev, { text, type, timestamp }]);
  }, []);

  const addFileHistoryEntry = useCallback((entry: Omit<FileHistoryEntry, 'id' | 'timestamp'>) => {
    const newEntry: FileHistoryEntry = {
      ...entry,
      id: Date.now(),
      timestamp: new Date().toISOString(),
    };
    setFileHistory(prev => [newEntry, ...prev]);
  }, []);

  const handleUserEnrolled = (newUser: User) => {
    setUsers(prevUsers => [...prevUsers, newUser]);
  };

  const handleDeleteUser = (userId: number) => {
    const userToDelete = users.find(u => u.id === userId);
    if(userToDelete) {
        setUsers(prev => prev.filter(u => u.id !== userId));
        addLog(`User '${userToDelete.name}' has been removed from the system.`, 'info');
    }
  };

  const handleStartEnrollment = () => {
    if (users.length >= MAX_USERS) {
      addLog(`Maximum user limit reached (${MAX_USERS}). Delete a user to add a new one.`, 'error');
      return;
    }
    setCurrentFlow('enroll');
    addLog("Initiating voice enrollment protocol.", 'info');
  };

  const handleStartEncryption = () => {
    if (users.filter(u => u.isEnrolled).length === 0) {
      addLog("Encryption requires at least one enrolled user.", 'error');
      return;
    }
    setCurrentFlow('encrypt');
    addLog("Initiating system-wide file encryption.", 'info');
  };

  const handleStartDecryption = () => {
    if (users.filter(u => u.isEnrolled).length === 0) {
      addLog("Decryption requires at least one enrolled user.", 'error');
      return;
    }
    setCurrentFlow('decrypt');
    addLog("Initiating biometric vault decryption.", 'info');
  };

  const handleFlowComplete = () => {
    setCurrentFlow(null);
    addLog('Operation flow ended.', 'info');
  };

  if (!isLoaded) {
    return (
      <div className="bg-gray-900 text-white min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500 mx-auto"></div>
          <p className="mt-4 text-gray-400">Booting Security System...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-gray-900 text-white min-h-screen font-sans">
      <Header />
      <main className="container mx-auto p-4 md:p-8 space-y-8">
        <FileActions
          onStartEnrollment={handleStartEnrollment}
          onStartEncryption={handleStartEncryption}
          onStartDecryption={handleStartDecryption}
        />
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1">
            <UserPanel users={users} onDeleteUser={handleDeleteUser} maxUsers={MAX_USERS} />
          </div>
          <div className="lg:col-span-2 space-y-8">
            <FileHistoryPanel history={fileHistory} />
            <SystemLog messages={logMessages} />
          </div>
        </div>
      </main>

      {currentFlow === 'enroll' && (
        <EnrollmentFlow 
          users={users}
          onComplete={handleFlowComplete} 
          onUserEnrolled={handleUserEnrolled} 
          addLog={addLog}
        />
      )}

      {currentFlow === 'encrypt' && (
        <EncryptionFlow 
          users={users.filter(u => u.isEnrolled)}
          onComplete={handleFlowComplete} 
          addLog={addLog}
          addFileHistoryEntry={addFileHistoryEntry}
        />
      )}

      {currentFlow === 'decrypt' && (
        <DecryptionFlow 
          users={users.filter(u => u.isEnrolled)}
          onComplete={handleFlowComplete} 
          addLog={addLog}
          addFileHistoryEntry={addFileHistoryEntry}
        />
      )}
    </div>
  );
};

export default App;

