            } else {
              onFailure("Voice profile mismatch. Identity rejected.");
            }
          } else if (action.type === 'identify') {
            let bestMatchUser: User | null = null;
            let highestScore = -1;

            for (const user of action.users) {
                if (user.voiceprint) {
                    const score = getVoiceSimilarityScore(currentVoiceprint, user.voiceprint);
                    if (score > highestScore) {
                        highestScore = score;
                        bestMatchUser = user;
                    }
                }
            }

            if (bestMatchUser && highestScore > SIMILARITY_THRESHOLD) {
                onSuccess({ user: bestMatchUser, voiceprint: currentVoiceprint });
            } else {
                onFailure("Voice not recognized in the secure database.");
            }
          }
        } catch (procError) {
          console.error("Audio Engine Error:", procError);
          setErrorMessage(procError instanceof VoiceProcessingError ? procError.message : "Internal audio analysis failure.");
          setStatus('error');
        }
      };

      mediaRecorderRef.current.start();
      setStatus('recording');
      setCountdown(RECORDING_DURATION_MS / 1000);

      countdownIntervalRef.current = window.setInterval(() => {
        setCountdown(prev => (prev > 1 ? prev - 1 : 0));
      }, 1000);

      recordingTimerRef.current = window.setTimeout(() => {
        stopRecording();
      }, RECORDING_DURATION_MS);

    } catch (err: any) {
      console.error("Hardware Access Error:", err);
      let msg = "Microphone access failed.";

      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        msg = "Microphone blocked. Please check site permissions in your browser's address bar.";
      } else if (err.name === 'NotFoundError') {
        msg = "No microphone hardware detected on this device.";
      } else if (err.message?.includes("HTTPS")) {
        msg = "Microphone requires a secure connection (HTTPS).";
      } else {
        msg = err.message || "Unknown hardware error occurred.";
      }

      setErrorMessage(msg);
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
    }
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      if (mediaRecorderRef.current?.stream) {
        mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const renderStatus = () => {
    switch (status) {
        case 'recording':
            return (
                <div className="text-center">
                    <div className="animate-pulse text-red-400 font-bold text-lg">RECORDING</div>
                    <p className="text-sm text-gray-400 mt-1">Listening... {countdown}s remaining</p>
                </div>
            );
        case 'processing':
             return (
                <div className="text-center flex flex-col items-center">
                    <SparklesIcon className="h-10 w-10 text-blue-400 animate-spin mb-2" />
                    <div className="text-blue-300 font-semibold">Comparing Voice Patterns...</div>
                </div>
            );
        case 'error':
            return (
                <div className="text-center px-4">
                    <div className="text-red-400 font-bold">ACCESS DENIED</div>
                    <p className="text-sm text-red-300 mt-1 leading-tight">{errorMessage}</p>
                </div>
            );
        default:
            return (
                 <div className="text-center">
                    <div className="font-bold text-white text-lg">{title}</div>
                    <p className="text-sm text-gray-400 mt-1 px-4">{instruction}</p>
                </div>
            );
    }
  };

  return (
    <div className="fixed inset-0 bg-gray-950/80 z-50 flex items-center justify-center p-4 backdrop-blur-md">
      <div className="bg-gray-900 rounded-3xl shadow-2xl w-full max-w-md p-8 border border-gray-800 relative ring-1 ring-white/10">
        <button onClick={onClose} className="absolute top-6 right-6 text-gray-500 hover:text-white transition-colors">
            <XMarkIcon className="h-6 w-6" />
        </button>
        <div className="space-y-8">
            <div className="h-24 flex items-center justify-center">{renderStatus()}</div>
            <div className="flex justify-center">
                 <button 
                    onClick={startRecording}
                    disabled={status !== 'idle'}
                    className={`
                        w-28 h-28 rounded-full flex items-center justify-center transition-all duration-500 shadow-2xl relative overflow-hidden
                        ${status === 'idle' ? 'bg-blue-600 hover:bg-blue-500 hover:scale-105 shadow-blue-500/30' : 'cursor-not-allowed scale-95'}
                        ${status === 'recording' ? 'bg-red-600 shadow-red-500/50' : ''}
                        ${(status === 'processing' || status === 'error') ? 'bg-gray-800 opacity-50' : ''}
                    `}
                    aria-label="Toggle Microphone"
                >
                    {status === 'recording' && (
                        <div className="absolute inset-0 border-4 border-white/20 rounded-full animate-ping"></div>
                    )}
                    <MicIcon className="h-12 w-12 text-white relative z-10" />
                </button>
            </div>
             {status === 'error' && (
                <button 
                  onClick={() => setStatus('idle')} 
                  className="w-full text-center text-blue-400 hover:text-blue-300 text-sm font-bold uppercase tracking-widest py-2"
                >
                    Retry Authorization
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

