import React, { useState, useCallback, useEffect } from 'react';
import Header from './components/Header';
import UserPanel from './components/UserPanel';
import SystemLog from './components/SystemLog';
import FileActions from './components/FileActions';
import EnrollmentFlow from './components/EnrollmentFlow';
import DecryptionFlow from './components/DecryptionFlow';
import EncryptionFlow from './components/EncryptionFlow';
import FileHistoryPanel from './components/FileHistoryPanel';
import { User, LogMessage, FileHistoryEntry } from './types';

type Flow = 'enroll' | 'encrypt' | 'decrypt' | null;
const MAX_USERS = 5;

const App: React.FC = () => {
  const [isLoaded, setIsLoaded] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [fileHistory, setFileHistory] = useState<FileHistoryEntry[]>([]);
  const [logMessages, setLogMessages] = useState<LogMessage[]>([]);
  const [currentFlow, setCurrentFlow] = useState<Flow>(null);

  // Initial load from localStorage - Run only once
  useEffect(() => {
    const initSystem = async () => {
      try {
        console.log("System: Starting biometric database recovery...");

        const savedUsers = localStorage.getItem('voiceAuthUsers_v2');
        if (savedUsers) {
          const parsed = JSON.parse(savedUsers);
          if (Array.isArray(parsed)) {
            const hydratedUsers = parsed.map((user: any) => ({
              ...user,
              // Crucial: Reconstruct Float32Array from stored standard array
              voiceprint: user.voiceprint ? new Float32Array(user.voiceprint) : null,
            }));
            setUsers(hydratedUsers);
            console.log(`System: Recovered ${hydratedUsers.length} user profiles.`);
          }
        }

        const savedHistory = localStorage.getItem('voiceAuthFileHistory_v2');
        if (savedHistory) {
          const parsedHistory = JSON.parse(savedHistory);
          if (Array.isArray(parsedHistory)) {
            setFileHistory(parsedHistory);
          }
        }

        addLog('Biometric database synchronized. Security modules online.', 'success');
      } catch (error) {
        console.error("System Error: Persistent storage recovery failed", error);
        addLog('Critical: Biometric storage recovery failed. Data might be inaccessible.', 'error');
      } finally {
        setIsLoaded(true);
      }
    };

    initSystem();
  }, []);

  // Save users whenever they change, but ONLY after initial load is complete
  useEffect(() => {
    if (!isLoaded) return;

    try {
      const serializableUsers = users.map(user => ({
        ...user,
        // Convert TypedArray back to standard array for JSON stringification
        voiceprint: user.voiceprint ? Array.from(user.voiceprint) : null,
      }));
      localStorage.setItem('voiceAuthUsers_v2', JSON.stringify(serializableUsers));
    } catch (error) {
       console.error("Storage Error: Failed to commit user profiles", error);
       if (error instanceof DOMException && error.name === 'QuotaExceededError') {
         addLog('Storage Limit Exceeded: Profile update failed.', 'error');
       }
    }
  }, [users, isLoaded]);

  // Save history whenever it changes
  useEffect(() => {
    if (!isLoaded) return;

    try {
      localStorage.setItem('voiceAuthFileHistory_v2', JSON.stringify(fileHistory));
    } catch (error) {
      console.error("Storage Error: Failed to commit history logs", error);
    }
  }, [fileHistory, isLoaded]);

  const addLog = useCallback((text: string, type: LogMessage['type']) => {
    const timestamp = new Date().toLocaleTimeString();
    setLogMessages(prev => [...prev, { text, type, timestamp }]);
  }, []);

  const addFileHistoryEntry = useCallback((entry: Omit<FileHistoryEntry, 'id' | 'timestamp'>) => {
    const newEntry: FileHistoryEntry = {
      ...entry,
      id: Date.now(),
      timestamp: new Date().toISOString(),
    };
    setFileHistory(prev => [newEntry, ...prev]);
  }, []);

  const handleUserEnrolled = (newUser: User) => {
    setUsers(prevUsers => [...prevUsers, newUser]);
  };

  const handleDeleteUser = (userId: number) => {
    const userToDelete = users.find(u => u.id === userId);
    if(userToDelete) {
        setUsers(prev => prev.filter(u => u.id !== userId));
        addLog(`User '${userToDelete.name}' profile decommissioned.`, 'info');
    }
  };

  const handleStartEnrollment = () => {
    if (users.length >= MAX_USERS) {
      addLog(`User capacity reached (${MAX_USERS}). Clear an existing profile to add more.`, 'error');
      return;
    }
    setCurrentFlow('enroll');
    addLog("Voice Enrollment Wizard activated.", 'info');
  };

  const handleStartEncryption = () => {
    if (users.filter(u => u.isEnrolled).length === 0) {
      addLog("System Guard: No enrolled voices found. Enrollment required for encryption.", 'error');
      return;
    }
    setCurrentFlow('encrypt');
    addLog("Initializing High-Level Encryption module.", 'info');
  };

  const handleStartDecryption = () => {
    if (users.filter(u => u.isEnrolled).length === 0) {
      addLog("System Guard: No enrolled voices found. Enrollment required for decryption.", 'error');
      return;
    }
    setCurrentFlow('decrypt');
    addLog("Accessing Biometric Decryption vault.", 'info');
  };

  const handleFlowComplete = () => {
    setCurrentFlow(null);
    addLog('Operation terminated. Protocol idle.', 'info');
  };

  if (!isLoaded) {
    return (
      <div className="bg-gray-950 text-white min-h-screen flex items-center justify-center font-mono">
        <div className="text-center space-y-6">
          <div className="relative h-24 w-24 mx-auto">
            <div className="absolute inset-0 border-4 border-blue-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-t-4 border-blue-500 rounded-full animate-spin"></div>
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-widest uppercase">System Initialization</h1>
            <p className="mt-2 text-blue-400 animate-pulse">Syncing Secure Database...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-gray-900 text-white min-h-screen font-sans selection:bg-blue-500/30">
      <Header />
      <main className="container mx-auto p-4 md:p-8 space-y-8 animate-in fade-in duration-700">
        <FileActions
          onStartEnrollment={handleStartEnrollment}
          onStartEncryption={handleStartEncryption}
          onStartDecryption={handleStartDecryption}
        />
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1">
            <UserPanel users={users} onDeleteUser={handleDeleteUser} maxUsers={MAX_USERS} />
          </div>
          <div className="lg:col-span-2 space-y-8">
            <FileHistoryPanel history={fileHistory} />
            <SystemLog messages={logMessages} />
          </div>
        </div>
      </main>

      {currentFlow === 'enroll' && (
        <EnrollmentFlow 
          users={users}
          onComplete={handleFlowComplete} 
          onUserEnrolled={handleUserEnrolled} 
          addLog={addLog}
        />
      )}

      {currentFlow === 'encrypt' && (
        <EncryptionFlow 
          users={users.filter(u => u.isEnrolled)}
          onComplete={handleFlowComplete} 
          addLog={addLog}
          addFileHistoryEntry={addFileHistoryEntry}
        />
      )}

      {currentFlow === 'decrypt' && (
        <DecryptionFlow 
          users={users.filter(u => u.isEnrolled)}
          onComplete={handleFlowComplete} 
          addLog={addLog}
          addFileHistoryEntry={addFileHistoryEntry}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AuthAction, User } from '../types';
import { MicIcon } from './icons/MicIcon';
import { XMarkIcon } from './icons/XMarkIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { generateVoiceprint, compareVoiceprints, getVoiceSimilarityScore, SIMILARITY_THRESHOLD, VoiceProcessingError } from '../utils/audioProcessor';

interface AuthModalProps {
  action: AuthAction;
  onClose: () => void;
  onSuccess: (result?: any) => void;
  onFailure: (reason: string) => void;
}

const RECORDING_DURATION_MS = 5000; 

const AuthModal: React.FC<AuthModalProps> = ({ action, onClose, onSuccess, onFailure }) => {
  const [status, setStatus] = useState<'idle' | 'recording' | 'processing' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [countdown, setCountdown] = useState(RECORDING_DURATION_MS / 1000);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number | null>(null);
  const countdownIntervalRef = useRef<number | null>(null);

  const title = action.type === 'enroll' ? 'Voice Enrollment' : 'Biometric Verification';
  const instruction = action.type === 'enroll'
    ? `Speak clearly: "Secure my data with the sound of my voice"`
    : `Repeat phrase: "Secure my data with the sound of my voice"`;

  const clearTimers = () => {
    if (recordingTimerRef.current) clearTimeout(recordingTimerRef.current);
    if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
  };

  const startRecording = async () => {
    if (status !== 'idle') return;

    setErrorMessage("");
    audioChunksRef.current = [];

    // Protocol Check: Secure context is required for microphone access in all modern browsers
    if (!window.isSecureContext) {
      setErrorMessage("Security Protocol Error: Microphone access is strictly blocked by your browser on insecure origins. Please ensure the URL starts with https:// or localhost.");
      setStatus('error');
      return;
    }

    try {
      // Check for API support
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Biometric capture device API (mediaDevices) not found in this environment.");
      }

      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: { 
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true
        }
      });

      const mimeType = MediaRecorder.isTypeSupported('audio/webm') 
        ? 'audio/webm' 
        : MediaRecorder.isTypeSupported('audio/ogg') 
          ? 'audio/ogg' 
          : '';

      mediaRecorderRef.current = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);

      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data);
      };

      mediaRecorderRef.current.onstop = async () => {
        setStatus('processing');
        stream.getTracks().forEach(track => track.stop());

        if (audioChunksRef.current.length === 0) {
          setErrorMessage("IO Error: Captured stream contains zero data. Check hardware connection.");
          setStatus('error');
          return;
        }

        try {
          const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });
          const currentVoiceprint = await generateVoiceprint(audioBlob);

          if (action.type === 'enroll') {
            onSuccess(currentVoiceprint);
          } else if (action.type === 'verify') {
            if (!action.user.voiceprint) {
              onFailure("Critical: Subject biometric data missing.");
              return;
            }
            if (compareVoiceprints(currentVoiceprint, action.user.voiceprint)) {
              onSuccess();
            } else {
              onFailure("Subject mismatch: Voice pattern does not align with database.");
            }
          } else if (action.type === 'identify') {
            let bestMatchUser: User | null = null;
            let highestScore = -1;

            for (const user of action.users) {
                if (user.voiceprint) {
                    const score = getVoiceSimilarityScore(currentVoiceprint, user.voiceprint);
                    if (score > highestScore) {
                        highestScore = score;
                        bestMatchUser = user;
                    }
                }
            }

            if (bestMatchUser && highestScore > SIMILARITY_THRESHOLD) {
                onSuccess({ user: bestMatchUser, voiceprint: currentVoiceprint });
            } else {
                onFailure("Identity unknown: No matching profile found in secure vault.");
            }
          }
        } catch (procError) {
          console.error("Biometric Engine Error:", procError);
          setErrorMessage(procError instanceof VoiceProcessingError ? procError.message : "Internal algorithmic analysis failure.");
          setStatus('error');
        }
      };

      mediaRecorderRef.current.start();
      setStatus('recording');
      setCountdown(RECORDING_DURATION_MS / 1000);

      countdownIntervalRef.current = window.setInterval(() => {
        setCountdown(prev => (prev > 1 ? prev - 1 : 0));
      }, 1000);

      recordingTimerRef.current = window.setTimeout(() => {
        stopRecording();
      }, RECORDING_DURATION_MS);

    } catch (err: any) {
      console.error("Hardware Initializer Error:", err);
      let msg = "Microphone access failed.";

      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        msg = "Access Denied: Microphone permission was rejected. Check the browser address bar icon to reset permissions.";
      } else if (err.name === 'NotFoundError') {
        msg = "Hardware Not Found: No microphone detected on this system.";
      } else {
        msg = err.message || "Unknown hardware/protocol error occurred.";
      }

      setErrorMessage(msg);
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
    }
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      if (mediaRecorderRef.current?.stream) {
        mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const renderStatus = () => {
    switch (status) {
        case 'recording':
            return (
                <div className="text-center">
                    <div className="flex items-center justify-center space-x-2">
                      <div className="h-2 w-2 bg-red-600 rounded-full animate-ping"></div>
                      <div className="text-red-500 font-bold tracking-[0.2em]">RECORDING</div>
                    </div>
                    <p className="text-xs text-gray-500 mt-2 uppercase">Time Remaining: {countdown}s</p>
                </div>
            );
        case 'processing':
             return (
                <div className="text-center flex flex-col items-center">
                    <SparklesIcon className="h-10 w-10 text-blue-500 animate-spin mb-3" />
                    <div className="text-blue-400 font-semibold tracking-wide">MATCHING WAVEFORMS...</div>
                </div>
            );
        case 'error':
            return (
                <div className="text-center px-4 space-y-2">
                    <div className="text-red-500 font-bold uppercase tracking-tight">Access Protocol Failure</div>
                    <p className="text-xs text-red-300 leading-relaxed font-mono">{errorMessage}</p>
                </div>
            );
        default:
            return (
                 <div className="text-center px-4">
                    <div className="font-bold text-white text-lg tracking-tight">{title}</div>
                    <p className="text-sm text-gray-500 mt-2 leading-relaxed">{instruction}</p>
                </div>
            );
    }
  };

  return (
    <div className="fixed inset-0 bg-gray-950/90 z-50 flex items-center justify-center p-4 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-gray-900/80 rounded-[2.5rem] shadow-2xl w-full max-w-md p-10 border border-white/5 relative overflow-hidden ring-1 ring-white/10">
        {/* Aesthetic background glow */}
        <div className="absolute -top-24 -left-24 w-48 h-48 bg-blue-500/10 blur-[100px] rounded-full"></div>
        <div className="absolute -bottom-24 -right-24 w-48 h-48 bg-purple-500/10 blur-[100px] rounded-full"></div>

        <button onClick={onClose} className="absolute top-8 right-8 text-gray-600 hover:text-white transition-colors z-20">
            <XMarkIcon className="h-6 w-6" />
        </button>

        <div className="space-y-10 relative z-10">
            <div className="h-28 flex items-center justify-center">{renderStatus()}</div>
            <div className="flex justify-center">
                 <button 
                    onClick={startRecording}
                    disabled={status !== 'idle'}
                    className={`
                        w-32 h-32 rounded-full flex items-center justify-center transition-all duration-700 shadow-2xl relative
                        ${status === 'idle' ? 'bg-blue-600 hover:bg-blue-500 hover:scale-110 shadow-blue-500/20 active:scale-95' : 'cursor-not-allowed'}
                        ${status === 'recording' ? 'bg-red-600 shadow-red-500/40' : ''}
                        ${(status === 'processing' || status === 'error') ? 'bg-gray-800 opacity-40 scale-90' : ''}
                    `}
                    aria-label="Toggle Biometric Capture"
                >
                    {status === 'recording' && (
                        <div className="absolute inset-0 border-8 border-white/10 rounded-full animate-ping"></div>
                    )}
                    <MicIcon className={`h-14 w-14 text-white transition-transform duration-500 ${status === 'recording' ? 'scale-110' : ''}`} />
                </button>
            </div>
             {status === 'error' && (
                <button 
                  onClick={() => setStatus('idle')} 
                  className="w-full text-center text-blue-500 hover:text-blue-400 text-xs font-bold uppercase tracking-[0.2em] py-4 transition-all"
                >
                    [ RE-INITIALIZE HARDWARE ]
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

export default AuthModal;

// Refined biometric engine for robust MFCC-based voice identification.
// Adjustments: Lowered threshold for usability, improved vector normalization.

export class VoiceProcessingError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'VoiceProcessingError';
  }
}

let audioCtx: AudioContext | null = null;

const getAudioContext = async (): Promise<AudioContext> => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
  // Explicitly resume every time we need it to prevent "suspended" state errors
  if (audioCtx.state === 'suspended') {
    await audioCtx.resume();
  }
  return audioCtx;
};

// --- MFCC Configuration ---
const NUM_MFCC_COEFFICIENTS = 13; 
const FFT_SIZE = 1024; 
const NUM_MEL_FILTERS = 40; 
const PRE_EMPHASIS_ALPHA = 0.97; 

// --- Voice Activity Detection (VAD) ---
const VAD_ENERGY_THRESHOLD = 0.005;

// --- Security Thresholds ---
// 0.96 is a good balance for consumer microphones. 
// Higher (0.99) often fails due to slight background noise.
export const SIMILARITY_THRESHOLD = 0.96; 
const MIN_REQUIRED_SPEECH_FRAMES = 30;

// --- DSP Helpers ---

const applyHammingWindow = (frame: Float32Array): void => {
    const N = frame.length;
    for (let i = 0; i < N; i++) {
        frame[i] *= 0.54 - 0.46 * Math.cos(2 * Math.PI * i / (N - 1));
    }
};

const fft = (input: Float32Array): { real: Float32Array; imag: Float32Array } => {
    const n = input.length;
    const real = new Float32Array(n);
    const imag = new Float32Array(n);
    const log2n = Math.log2(n);
    for (let i = 0; i < n; i++) {
        let rev = 0;
        for (let j = 0; j < log2n; j++) if ((i >> j) & 1) rev |= 1 << (log2n - 1 - j);
        real[rev] = input[i];
    }
    for (let size = 2; size <= n; size *= 2) {
        const halfSize = size / 2;
        const angleStep = -2 * Math.PI / size;
        for (let i = 0; i < n; i += size) {
            for (let j = 0; j < halfSize; j++) {
                const angle = j * angleStep;
                const w_real = Math.cos(angle);
                const w_imag = Math.sin(angle);
                const k = i + j;
                const l = k + halfSize;
                const t_real = real[l] * w_real - imag[l] * w_imag;
                const t_imag = real[l] * w_imag + imag[l] * w_real;
                real[l] = real[k] - t_real;
                imag[l] = imag[k] - t_imag;
                real[k] += t_real;
                imag[k] += t_imag;
            }
        }
    }
    return { real, imag };
}

const hzToMel = (hz: number): number => 2595 * Math.log10(1 + hz / 700);
const melToHz = (mel: number): number => 700 * (Math.pow(10, mel / 2595) - 1);

const createMelFilterbank = (fftSize: number, numFilters: number, sampleRate: number): number[][] => {
  const fMax = sampleRate / 2;
  const melMax = hzToMel(fMax);
  const melMin = hzToMel(0);
  const melPoints = new Float32Array(numFilters + 2);
  for (let i = 0; i < melPoints.length; i++) melPoints[i] = melMin + i * (melMax - melMin) / (numFilters + 1);
  const hzPoints = melPoints.map(mel => melToHz(mel));
  const binPoints = hzPoints.map(hz => Math.floor((fftSize + 1) * hz / sampleRate));
  const filterbank: number[][] = [];
  for (let i = 0; i < numFilters; i++) {
    const filter = new Array(Math.floor(fftSize / 2) + 1).fill(0);
    for (let j = binPoints[i]; j < binPoints[i + 1]; j++) filter[j] = (j - binPoints[i]) / (binPoints[i + 1] - binPoints[i]);
    for (let j = binPoints[i + 1]; j < binPoints[i + 2]; j++) filter[j] = (binPoints[i + 2] - j) / (binPoints[i + 2] - binPoints[i + 1]);
    filterbank.push(filter);
  }
  return filterbank;
};

const dct = (input: Float32Array, numCoefficients: number): Float32Array => {
    const N = input.length;
    const output = new Float32Array(numCoefficients);
    for (let k = 0; k < numCoefficients; k++) {
      let sum = 0;
      for (let n = 0; n < N; n++) sum += input[n] * Math.cos(Math.PI * k * (2 * n + 1) / (2 * N));
      output[k] = sum * Math.sqrt((k === 0 ? 1 : 2) / N);
    }
    return output;
};

export const generateVoiceprint = async (audioBlob: Blob): Promise<Float32Array> => {
  const ctx = await getAudioContext();
  const arrayBuffer = await audioBlob.arrayBuffer();

  // Handling for empty/corrupt files
  if (arrayBuffer.byteLength === 0) throw new VoiceProcessingError("Audio capture was empty.");

  const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
  const pcmData = audioBuffer.getChannelData(0);

  // Pre-emphasis
  const emphasizedPcm = new Float32Array(pcmData.length);
  emphasizedPcm[0] = pcmData[0];
  for (let i = 1; i < pcmData.length; i++) emphasizedPcm[i] = pcmData[i] - PRE_EMPHASIS_ALPHA * pcmData[i - 1];

  const melFilterbank = createMelFilterbank(FFT_SIZE, NUM_MEL_FILTERS, audioBuffer.sampleRate);
  const allMfccs: Float32Array[] = [];
  const hopLength = Math.round(audioBuffer.sampleRate * 0.010); // 10ms hop

  for (let i = 0; i + FFT_SIZE <= emphasizedPcm.length; i += hopLength) {
      const frame = emphasizedPcm.slice(i, i + FFT_SIZE);
      let energy = 0;
      for (const sample of frame) energy += sample * sample;
      energy = Math.sqrt(energy / frame.length);

      if (energy < VAD_ENERGY_THRESHOLD) continue;

      applyHammingWindow(frame);
      const { real, imag } = fft(frame);
      const powerSpectrum = new Float32Array(FFT_SIZE / 2 + 1);
      for (let k = 0; k < powerSpectrum.length; k++) powerSpectrum[k] = (real[k] * real[k] + imag[k] * imag[k]) / FFT_SIZE;

      const melEnergies = new Float32Array(NUM_MEL_FILTERS).fill(0);
      for (let j = 0; j < NUM_MEL_FILTERS; j++) {
          for (let k = 0; k < powerSpectrum.length; k++) melEnergies[j] += melFilterbank[j][k] * powerSpectrum[k];
      }

      const logMelEnergies = melEnergies.map(e => Math.log(Math.max(e, 1e-10)));
      allMfccs.push(dct(logMelEnergies, NUM_MFCC_COEFFICIENTS));
  }

  if (allMfccs.length < MIN_REQUIRED_SPEECH_FRAMES) {
      throw new VoiceProcessingError("Speech too short or quiet. Please speak louder and longer.");
  }

  // Average MFCCs across frames
  const voiceprint = new Float32Array(NUM_MFCC_COEFFICIENTS).fill(0);
  for (const frame of allMfccs) {
      for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) voiceprint[j] += frame[j];
  }
  for (let i = 0; i < voiceprint.length; i++) voiceprint[i] /= allMfccs.length;

  // Final Vector Normalization
  const mag = Math.sqrt(voiceprint.reduce((s, v) => s + v * v, 0));
  return mag > 0 ? voiceprint.map(v => v / mag) : voiceprint;
};

export const getVoiceSimilarityScore = (vp1: Float32Array, vp2: Float32Array): number => {
  if (vp1.length !== vp2.length) return 0;
  let dotProduct = 0;
  for (let i = 0; i < vp1.length; i++) dotProduct += vp1[i] * vp2[i];
  return dotProduct;
};

export const compareVoiceprints = (vp1: Float32Array | null, vp2: Float32Array | null): boolean => {
  if (!vp1 || !vp2) return false;
  const score = getVoiceSimilarityScore(vp1, vp2);
  console.log(`[Biometric Analysis] Match Score: ${score.toFixed(4)} (Required: ${SIMILARITY_THRESHOLD})`);
  return score >= SIMILARITY_THRESHOLD;
};

import React, { useState, useEffect, useRef } from 'react';
import { AuthAction, User } from '../types';
import { MicIcon } from './icons/MicIcon';
import { XMarkIcon } from './icons/XMarkIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { generateVoiceprint, compareVoiceprints, getVoiceSimilarityScore, SIMILARITY_THRESHOLD, VoiceProcessingError } from '../utils/audioProcessor';

interface AuthModalProps {
  action: AuthAction;
  onClose: () => void;
  onSuccess: (result?: any) => void;
  onFailure: (reason: string) => void;
}

const RECORDING_DURATION_MS = 5000; 

const AuthModal: React.FC<AuthModalProps> = ({ action, onClose, onSuccess, onFailure }) => {
  const [status, setStatus] = useState<'idle' | 'recording' | 'processing' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [countdown, setCountdown] = useState(RECORDING_DURATION_MS / 1000);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number | null>(null);
  const countdownIntervalRef = useRef<number | null>(null);

  const title = action.type === 'enroll' ? 'Voice Enrollment' : 'Biometric Verification';
  const phrase = "Secure my data with the sound of my voice";

  const clearTimers = () => {
    if (recordingTimerRef.current) clearTimeout(recordingTimerRef.current);
    if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
  };

  const startRecording = async () => {
    if (status !== 'idle') return;

    setErrorMessage("");
    audioChunksRef.current = [];

    if (!window.isSecureContext) {
      setErrorMessage("HTTPS Required: Chrome blocks microphone access on insecure connections. Please use https:// or localhost.");
      setStatus('error');
      return;
    }

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Biometric API not supported by this browser.");
      }

      // Request stream with high-quality constraints
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: { 
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true
        }
      });

      const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : '';
      mediaRecorderRef.current = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);

      mediaRecorderRef.current.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      mediaRecorderRef.current.onstop = async () => {
        setStatus('processing');
        stream.getTracks().forEach(t => t.stop());

        if (audioChunksRef.current.length === 0) {
          setErrorMessage("IO Error: No audio data captured. Please verify microphone connection.");
          setStatus('error');
          return;
        }

        try {
          const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });
          const currentVoiceprint = await generateVoiceprint(audioBlob);

          if (action.type === 'enroll') {
            onSuccess(currentVoiceprint);
          } else if (action.type === 'verify' || action.type === 'identify') {
            const usersToSearch = action.type === 'verify' ? [action.user] : action.users;
            let bestMatch: User | null = null;
            let maxScore = -1;

            for (const user of usersToSearch) {
              if (user.voiceprint) {
                const score = getVoiceSimilarityScore(currentVoiceprint, user.voiceprint);
                if (score > maxScore) {
                  maxScore = score;
                  bestMatch = user;
                }
              }
            }

            console.log(`[Verification] Best Match: ${bestMatch?.name || 'None'}, Score: ${maxScore.toFixed(4)}`);

            if (bestMatch && maxScore >= SIMILARITY_THRESHOLD) {
              onSuccess(action.type === 'identify' ? { user: bestMatch, voiceprint: currentVoiceprint } : undefined);
            } else {
              onFailure("Identity rejected: Voice does not match enrolled profile.");
            }
          }
        } catch (err) {
          setErrorMessage(err instanceof VoiceProcessingError ? err.message : "Analysis failed.");
          setStatus('error');
        }
      };

      // Hardware stabilization delay: wait 300ms for AGC/Noise suppression to "warm up"
      await new Promise(r => setTimeout(r, 300));

      mediaRecorderRef.current.start();
      setStatus('recording');
      setCountdown(RECORDING_DURATION_MS / 1000);

      countdownIntervalRef.current = window.setInterval(() => setCountdown(p => (p > 1 ? p - 1 : 0)), 1000);
      recordingTimerRef.current = window.setTimeout(() => stopRecording(), RECORDING_DURATION_MS);

    } catch (err: any) {
      console.error("Mic Access Error:", err);
      let msg = "Microphone failed.";
      if (err.name === 'NotAllowedError') msg = "Permission Denied: Please allow microphone access in your browser settings (click the lock icon in the URL bar).";
      else if (err.name === 'NotFoundError') msg = "Hardware Not Found: Plug in a microphone to continue.";
      setErrorMessage(msg);
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') mediaRecorderRef.current.stop();
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      mediaRecorderRef.current?.stream.getTracks().forEach(t => t.stop());
    };
  }, []);

  return (
    <div className="fixed inset-0 bg-gray-950/90 z-50 flex items-center justify-center p-4 backdrop-blur-xl transition-all duration-300">
      <div className="bg-gray-900 border border-white/10 rounded-[2rem] shadow-2xl w-full max-w-md p-10 relative ring-1 ring-white/5 overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-600 via-purple-600 to-blue-600 animate-pulse"></div>

        <button onClick={onClose} className="absolute top-6 right-6 text-gray-500 hover:text-white transition-colors z-20">
            <XMarkIcon className="h-6 w-6" />
        </button>

        <div className="space-y-10">
            <div className="text-center h-24 flex flex-col justify-center">
                {status === 'recording' ? (
                    <div className="space-y-2">
                      <div className="flex items-center justify-center space-x-2">
                        <div className="h-2 w-2 bg-red-600 rounded-full animate-ping"></div>
                        <span className="text-red-500 font-bold tracking-[0.2em] uppercase">Recording</span>
                      </div>
                      <p className="text-sm text-gray-400">Capture ends in {countdown}s</p>
                    </div>
                ) : status === 'processing' ? (
                    <div className="flex flex-col items-center animate-pulse">
                        <SparklesIcon className="h-10 w-10 text-blue-500 mb-2 animate-spin" />
                        <span className="text-blue-400 font-bold uppercase tracking-widest">Validating Waveform...</span>
                    </div>
                ) : status === 'error' ? (
                    <div className="px-2">
                        <h4 className="text-red-500 font-bold uppercase mb-1">Access Protocol Failed</h4>
                        <p className="text-xs text-red-300/80 leading-relaxed">{errorMessage}</p>
                    </div>
                ) : (
                    <div className="space-y-1">
                        <h2 className="text-xl font-bold text-white tracking-tight">{title}</h2>
                        <p className="text-sm text-gray-500 leading-relaxed italic">" {phrase} "</p>
                    </div>
                )}
            </div>

            <div className="flex justify-center">
                 <button 
                    onClick={startRecording}
                    disabled={status !== 'idle'}
                    className={`
                        w-32 h-32 rounded-full flex items-center justify-center transition-all duration-700 relative group
                        ${status === 'idle' ? 'bg-blue-600 hover:bg-blue-500 hover:scale-110 shadow-[0_0_30px_rgba(37,99,235,0.3)]' : 'cursor-not-allowed scale-90'}
                        ${status === 'recording' ? 'bg-red-600 shadow-[0_0_40px_rgba(220,38,38,0.4)]' : ''}
                        ${(status === 'processing' || status === 'error') ? 'bg-gray-800 opacity-30' : ''}
                    `}
                >
                    {status === 'recording' && (
                        <div className="absolute inset-0 border-8 border-white/20 rounded-full animate-ping"></div>
                    )}
                    <MicIcon className={`h-14 w-14 text-white transition-transform ${status === 'recording' ? 'scale-110' : ''}`} />
                </button>
            </div>

             {status === 'error' && (
                <button onClick={() => setStatus('idle')} className="w-full text-blue-500 hover:text-blue-400 text-xs font-bold uppercase tracking-widest pt-4">
                    [ Restart Protocol ]
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

export default AuthModal;

// Advanced biometric engine for MFCC-based speaker verification.
// Enhanced with robust VAD and vector normalization for real-world reliability.

export class VoiceProcessingError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'VoiceProcessingError';
  }
}

let audioCtx: AudioContext | null = null;

const getAudioContext = async (): Promise<AudioContext> => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
  if (audioCtx.state === 'suspended') {
    await audioCtx.resume();
  }
  return audioCtx;
};

// --- MFCC Configuration ---
const NUM_MFCC_COEFFICIENTS = 13; 
const FFT_SIZE = 1024; 
const NUM_MEL_FILTERS = 40; 
const PRE_EMPHASIS_ALPHA = 0.97; 

// --- Voice Activity Detection (VAD) ---
// Increased energy threshold to filter out background hum more aggressively
const VAD_ENERGY_THRESHOLD = 0.015;

// --- Security Thresholds ---
// 0.88 is a balanced threshold for speaker verification using simple MFCC averaging.
// Previous 0.96 was too strict for varying environmental conditions.
export const SIMILARITY_THRESHOLD = 0.88; 
const MIN_REQUIRED_SPEECH_FRAMES = 25;

// --- DSP Helpers ---

const applyHammingWindow = (frame: Float32Array): void => {
    const N = frame.length;
    for (let i = 0; i < N; i++) {
        frame[i] *= 0.54 - 0.46 * Math.cos(2 * Math.PI * i / (N - 1));
    }
};

const fft = (input: Float32Array): { real: Float32Array; imag: Float32Array } => {
    const n = input.length;
    const real = new Float32Array(n);
    const imag = new Float32Array(n);
    const log2n = Math.log2(n);
    for (let i = 0; i < n; i++) {
        let rev = 0;
        for (let j = 0; j < log2n; j++) if ((i >> j) & 1) rev |= 1 << (log2n - 1 - j);
        real[rev] = input[i];
    }
    for (let size = 2; size <= n; size *= 2) {
        const halfSize = size / 2;
        const angleStep = -2 * Math.PI / size;
        for (let i = 0; i < n; i += size) {
            for (let j = 0; j < halfSize; j++) {
                const angle = j * angleStep;
                const w_real = Math.cos(angle);
                const w_imag = Math.sin(angle);
                const k = i + j;
                const l = k + halfSize;
                const t_real = real[l] * w_real - imag[l] * w_imag;
                const t_imag = real[l] * w_imag + imag[l] * w_real;
                real[l] = real[k] - t_real;
                imag[l] = imag[k] - t_imag;
                real[k] += t_real;
                imag[k] += t_imag;
            }
        }
    }
    return { real, imag };
}

const hzToMel = (hz: number): number => 2595 * Math.log10(1 + hz / 700);
const melToHz = (mel: number): number => 700 * (Math.pow(10, mel / 2595) - 1);

const createMelFilterbank = (fftSize: number, numFilters: number, sampleRate: number): number[][] => {
  const fMax = sampleRate / 2;
  const melMax = hzToMel(fMax);
  const melMin = hzToMel(0);
  const melPoints = new Float32Array(numFilters + 2);
  for (let i = 0; i < melPoints.length; i++) melPoints[i] = melMin + i * (melMax - melMin) / (numFilters + 1);
  const hzPoints = melPoints.map(mel => melToHz(mel));
  const binPoints = hzPoints.map(hz => Math.floor((fftSize + 1) * hz / sampleRate));
  const filterbank: number[][] = [];
  for (let i = 0; i < numFilters; i++) {
    const filter = new Array(Math.floor(fftSize / 2) + 1).fill(0);
    for (let j = binPoints[i]; j < binPoints[i + 1]; j++) filter[j] = (j - binPoints[i]) / (binPoints[i + 1] - binPoints[i]);
    for (let j = binPoints[i + 1]; j < binPoints[i + 2]; j++) filter[j] = (binPoints[i + 2] - j) / (binPoints[i + 2] - binPoints[i + 1]);
    filterbank.push(filter);
  }
  return filterbank;
};

const dct = (input: Float32Array, numCoefficients: number): Float32Array => {
    const N = input.length;
    const output = new Float32Array(numCoefficients);
    for (let k = 0; k < numCoefficients; k++) {
      let sum = 0;
      for (let n = 0; n < N; n++) sum += input[n] * Math.cos(Math.PI * k * (2 * n + 1) / (2 * N));
      output[k] = sum * Math.sqrt((k === 0 ? 1 : 2) / N);
    }
    return output;
};

export const generateVoiceprint = async (audioBlob: Blob): Promise<Float32Array> => {
  const ctx = await getAudioContext();
  const arrayBuffer = await audioBlob.arrayBuffer();

  if (arrayBuffer.byteLength === 0) throw new VoiceProcessingError("Audio capture was empty.");

  const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
  const pcmData = audioBuffer.getChannelData(0);

  // Pre-emphasis filter to boost higher frequencies (speech clarity)
  const emphasizedPcm = new Float32Array(pcmData.length);
  emphasizedPcm[0] = pcmData[0];
  for (let i = 1; i < pcmData.length; i++) emphasizedPcm[i] = pcmData[i] - PRE_EMPHASIS_ALPHA * pcmData[i - 1];

  const melFilterbank = createMelFilterbank(FFT_SIZE, NUM_MEL_FILTERS, audioBuffer.sampleRate);
  const allMfccs: Float32Array[] = [];
  const hopLength = Math.round(audioBuffer.sampleRate * 0.010); 

  for (let i = 0; i + FFT_SIZE <= emphasizedPcm.length; i += hopLength) {
      const frame = emphasizedPcm.slice(i, i + FFT_SIZE);
      let energy = 0;
      for (const sample of frame) energy += sample * sample;
      energy = Math.sqrt(energy / frame.length);

      // Skip non-speech frames
      if (energy < VAD_ENERGY_THRESHOLD) continue;

      applyHammingWindow(frame);
      const { real, imag } = fft(frame);
      const powerSpectrum = new Float32Array(FFT_SIZE / 2 + 1);
      for (let k = 0; k < powerSpectrum.length; k++) powerSpectrum[k] = (real[k] * real[k] + imag[k] * imag[k]) / FFT_SIZE;

      const melEnergies = new Float32Array(NUM_MEL_FILTERS).fill(0);
      for (let j = 0; j < NUM_MEL_FILTERS; j++) {
          for (let k = 0; k < powerSpectrum.length; k++) melEnergies[j] += melFilterbank[j][k] * powerSpectrum[k];
      }

      const logMelEnergies = melEnergies.map(e => Math.log(Math.max(e, 1e-10)));
      allMfccs.push(dct(logMelEnergies, NUM_MFCC_COEFFICIENTS));
  }

  if (allMfccs.length < MIN_REQUIRED_SPEECH_FRAMES) {
      throw new VoiceProcessingError("Speech not detected. Please speak closer to the microphone and follow the phrase.");
  }

  // Create a centroid (average) vector of the user's MFCC frames
  const voiceprint = new Float32Array(NUM_MFCC_COEFFICIENTS).fill(0);
  for (const frame of allMfccs) {
      for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) voiceprint[j] += frame[j];
  }
  for (let i = 0; i < voiceprint.length; i++) voiceprint[i] /= allMfccs.length;

  // Final Vector Normalization to Unit Length (Sphere Projection)
  const mag = Math.sqrt(voiceprint.reduce((s, v) => s + v * v, 0));
  return mag > 0 ? voiceprint.map(v => v / mag) : voiceprint;
};

export const getVoiceSimilarityScore = (vp1: Float32Array, vp2: Float32Array): number => {
  if (vp1.length !== vp2.length) return 0;
  // Cosine Similarity between two normalized MFCC centroids
  let dotProduct = 0;
  for (let i = 0; i < vp1.length; i++) dotProduct += vp1[i] * vp2[i];
  return dotProduct;
};

export const compareVoiceprints = (vp1: Float32Array | null, vp2: Float32Array | null): boolean => {
  if (!vp1 || !vp2) return false;
  const score = getVoiceSimilarityScore(vp1, vp2);
  console.log(`[Biometric Logic] Verification Score: ${score.toFixed(4)} | Threshold: ${SIMILARITY_THRESHOLD}`);
  return score >= SIMILARITY_THRESHOLD;
};

