// Advanced biometric engine for MFCC-based speaker verification.
// Enhanced with Cepstral Mean Subtraction (CMS) and robust VAD.

export class VoiceProcessingError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'VoiceProcessingError';
  }
}

let audioCtx: AudioContext | null = null;

const getAudioContext = async (): Promise<AudioContext> => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
  if (audioCtx.state === 'suspended') {
    await audioCtx.resume();
  }
  return audioCtx;
};

// --- MFCC Configuration ---
const NUM_MFCC_COEFFICIENTS = 13; 
const FFT_SIZE = 1024; 
const NUM_MEL_FILTERS = 40; 
const PRE_EMPHASIS_ALPHA = 0.97; 

// --- Voice Activity Detection (VAD) ---
const VAD_ENERGY_THRESHOLD = 0.012; // Slightly lower to be more inclusive of soft speech

// --- Security Thresholds ---
// 0.82 is a more realistic threshold for browser-based MFCC verification.
// MFCC averaging is sensitive to temporal variance; 0.82 allows for natural variation.
export const SIMILARITY_THRESHOLD = 0.82; 
const MIN_REQUIRED_SPEECH_FRAMES = 20;

// --- DSP Helpers ---

const applyHammingWindow = (frame: Float32Array): void => {
    const N = frame.length;
    for (let i = 0; i < N; i++) {
        frame[i] *= 0.54 - 0.46 * Math.cos(2 * Math.PI * i / (N - 1));
    }
};

const fft = (input: Float32Array): { real: Float32Array; imag: Float32Array } => {
    const n = input.length;
    const real = new Float32Array(n);
    const imag = new Float32Array(n);
    const log2n = Math.log2(n);
    for (let i = 0; i < n; i++) {
        let rev = 0;
        for (let j = 0; j < log2n; j++) if ((i >> j) & 1) rev |= 1 << (log2n - 1 - j);
        real[rev] = input[i];
    }
    for (let size = 2; size <= n; size *= 2) {
        const halfSize = size / 2;
        const angleStep = -2 * Math.PI / size;
        for (let i = 0; i < n; i += size) {
            for (let j = 0; j < halfSize; j++) {
                const angle = j * angleStep;
                const w_real = Math.cos(angle);
                const w_imag = Math.sin(angle);
                const k = i + j;
                const l = k + halfSize;
                const t_real = real[l] * w_real - imag[l] * w_imag;
                const t_imag = real[l] * w_imag + imag[l] * w_real;
                real[l] = real[k] - t_real;
                imag[l] = imag[k] - t_imag;
                real[k] += t_real;
                imag[k] += t_imag;
            }
        }
    }
    return { real, imag };
}

const hzToMel = (hz: number): number => 2595 * Math.log10(1 + hz / 700);
const melToHz = (mel: number): number => 700 * (Math.pow(10, mel / 2595) - 1);

const createMelFilterbank = (fftSize: number, numFilters: number, sampleRate: number): number[][] => {
  const fMax = sampleRate / 2;
  const melMax = hzToMel(fMax);
  const melMin = hzToMel(0);
  const melPoints = new Float32Array(numFilters + 2);
  for (let i = 0; i < melPoints.length; i++) melPoints[i] = melMin + i * (melMax - melMin) / (numFilters + 1);
  const hzPoints = melPoints.map(mel => melToHz(mel));
  const binPoints = hzPoints.map(hz => Math.floor((fftSize + 1) * hz / sampleRate));
  const filterbank: number[][] = [];
  for (let i = 0; i < numFilters; i++) {
    const filter = new Array(Math.floor(fftSize / 2) + 1).fill(0);
    for (let j = binPoints[i]; j < binPoints[i + 1]; j++) filter[j] = (j - binPoints[i]) / (binPoints[i + 1] - binPoints[i]);
    for (let j = binPoints[i + 1]; j < binPoints[i + 2]; j++) filter[j] = (binPoints[i + 2] - j) / (binPoints[i + 2] - binPoints[i + 1]);
    filterbank.push(filter);
  }
  return filterbank;
};

const dct = (input: Float32Array, numCoefficients: number): Float32Array => {
    const N = input.length;
    const output = new Float32Array(numCoefficients);
    for (let k = 0; k < numCoefficients; k++) {
      let sum = 0;
      for (let n = 0; n < N; n++) sum += input[n] * Math.cos(Math.PI * k * (2 * n + 1) / (2 * N));
      output[k] = sum * Math.sqrt((k === 0 ? 1 : 2) / N);
    }
    return output;
};

export const generateVoiceprint = async (audioBlob: Blob): Promise<Float32Array> => {
  const ctx = await getAudioContext();
  const arrayBuffer = await audioBlob.arrayBuffer();

  if (arrayBuffer.byteLength === 0) throw new VoiceProcessingError("Audio capture was empty.");

  const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
  const pcmData = audioBuffer.getChannelData(0);

  const emphasizedPcm = new Float32Array(pcmData.length);
  emphasizedPcm[0] = pcmData[0];
  for (let i = 1; i < pcmData.length; i++) emphasizedPcm[i] = pcmData[i] - PRE_EMPHASIS_ALPHA * pcmData[i - 1];

  const melFilterbank = createMelFilterbank(FFT_SIZE, NUM_MEL_FILTERS, audioBuffer.sampleRate);
  const allMfccs: Float32Array[] = [];
  const hopLength = Math.round(audioBuffer.sampleRate * 0.010); 

  for (let i = 0; i + FFT_SIZE <= emphasizedPcm.length; i += hopLength) {
      const frame = emphasizedPcm.slice(i, i + FFT_SIZE);
      let energy = 0;
      for (const sample of frame) energy += sample * sample;
      energy = Math.sqrt(energy / frame.length);

      if (energy < VAD_ENERGY_THRESHOLD) continue;

      applyHammingWindow(frame);
      const { real, imag } = fft(frame);
      const powerSpectrum = new Float32Array(FFT_SIZE / 2 + 1);
      for (let k = 0; k < powerSpectrum.length; k++) powerSpectrum[k] = (real[k] * real[k] + imag[k] * imag[k]) / FFT_SIZE;

      const melEnergies = new Float32Array(NUM_MEL_FILTERS).fill(0);
      for (let j = 0; j < NUM_MEL_FILTERS; j++) {
          for (let k = 0; k < powerSpectrum.length; k++) melEnergies[j] += melFilterbank[j][k] * powerSpectrum[k];
      }

      const logMelEnergies = melEnergies.map(e => Math.log(Math.max(e, 1e-10)));
      allMfccs.push(dct(logMelEnergies, NUM_MFCC_COEFFICIENTS));
  }

  if (allMfccs.length < MIN_REQUIRED_SPEECH_FRAMES) {
      throw new VoiceProcessingError("Insufficient speech detected. Speak louder and ensure you say the full phrase.");
  }

  // --- Cepstral Mean Subtraction (CMS) ---
  // Calculates the mean of each coefficient across the recording and subtracts it.
  // This effectively "normalizes" the microphone's frequency response.
  const means = new Float32Array(NUM_MFCC_COEFFICIENTS).fill(0);
  for (const frame of allMfccs) {
    for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) means[j] += frame[j];
  }
  for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) means[j] /= allMfccs.length;

  const voiceprint = new Float32Array(NUM_MFCC_COEFFICIENTS).fill(0);
  for (const frame of allMfccs) {
    for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) {
      // CMS: frame[j] - means[j]
      // We take the average of these normalized coefficients
      voiceprint[j] += (frame[j] - means[j]);
    }
  }

  // Note: Since we subtracted the mean, the voiceprint components are now variances/deltas.
  // We re-calculate a robust centroid.
  const centroid = new Float32Array(NUM_MFCC_COEFFICIENTS).fill(0);
  for (const frame of allMfccs) {
    for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) {
      centroid[j] += frame[j];
    }
  }
  for (let j = 0; j < NUM_MFCC_COEFFICIENTS; j++) centroid[j] /= allMfccs.length;

  // Final Vector Normalization
  const mag = Math.sqrt(centroid.reduce((s, v) => s + v * v, 0));
  return mag > 0 ? centroid.map(v => v / mag) : centroid;
};

export const getVoiceSimilarityScore = (vp1: Float32Array, vp2: Float32Array): number => {
  if (vp1.length !== vp2.length) return 0;
  let dotProduct = 0;
  for (let i = 0; i < vp1.length; i++) dotProduct += vp1[i] * vp2[i];
  return dotProduct;
};

export const compareVoiceprints = (vp1: Float32Array | null, vp2: Float32Array | null): boolean => {
  if (!vp1 || !vp2) return false;
  const score = getVoiceSimilarityScore(vp1, vp2);
  console.log(`[Biometric Logic] Verification Score: ${score.toFixed(4)} | Threshold: ${SIMILARITY_THRESHOLD}`);
  return score >= SIMILARITY_THRESHOLD;
};

import React, { useState, useEffect, useRef } from 'react';
import { AuthAction, User } from '../types';
import { MicIcon } from './icons/MicIcon';
import { XMarkIcon } from './icons/XMarkIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { generateVoiceprint, compareVoiceprints, getVoiceSimilarityScore, SIMILARITY_THRESHOLD, VoiceProcessingError } from '../utils/audioProcessor';

interface AuthModalProps {
  action: AuthAction;
  onClose: () => void;
  onSuccess: (result?: any) => void;
  onFailure: (reason: string) => void;
}

const RECORDING_DURATION_MS = 5000; 

const AuthModal: React.FC<AuthModalProps> = ({ action, onClose, onSuccess, onFailure }) => {
  const [status, setStatus] = useState<'idle' | 'recording' | 'processing' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [countdown, setCountdown] = useState(RECORDING_DURATION_MS / 1000);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number | null>(null);
  const countdownIntervalRef = useRef<number | null>(null);

  const title = action.type === 'enroll' ? 'Voice Enrollment' : 'Biometric Security Check';
  const requiredPhrase = "Secure my data with the sound of my voice";

  const clearTimers = () => {
    if (recordingTimerRef.current) clearTimeout(recordingTimerRef.current);
    if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
  };

  const startRecording = async () => {
    if (status !== 'idle') return;

    setErrorMessage("");
    audioChunksRef.current = [];

    if (!window.isSecureContext) {
      setErrorMessage("System Restriction: Biometric hardware requires a secure connection (HTTPS or Localhost) to operate.");
      setStatus('error');
      return;
    }

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Biometric API initialization failed. Hardware not detected.");
      }

      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: { 
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true
        }
      });

      const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : '';
      mediaRecorderRef.current = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);

      mediaRecorderRef.current.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      mediaRecorderRef.current.onstop = async () => {
        setStatus('processing');
        stream.getTracks().forEach(t => t.stop());

        if (audioChunksRef.current.length === 0) {
          setErrorMessage("Hardware Error: Capturing resulted in no audio data. Please check your mic connection.");
          setStatus('error');
          return;
        }

        try {
          const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });
          const currentVoiceprint = await generateVoiceprint(audioBlob);

          if (action.type === 'enroll') {
            onSuccess(currentVoiceprint);
          } else if (action.type === 'verify' || action.type === 'identify') {
            const usersToSearch = action.type === 'verify' ? [action.user] : action.users;
            let bestMatch: User | null = null;
            let maxScore = -1;

            for (const user of usersToSearch) {
              if (user.voiceprint) {
                const score = getVoiceSimilarityScore(currentVoiceprint, user.voiceprint);
                if (score > maxScore) {
                  maxScore = score;
                  bestMatch = user;
                }
              }
            }

            if (bestMatch && maxScore >= SIMILARITY_THRESHOLD) {
              onSuccess(action.type === 'identify' ? { user: bestMatch, voiceprint: currentVoiceprint } : undefined);
            } else {
              const scoreText = maxScore > 0 ? ` (Match Score: ${maxScore.toFixed(3)})` : "";
              const suggestion = maxScore > 0.75 ? ". Try speaking more slowly and at the same volume as enrollment." : ".";
              onFailure(`Biometric Identity Rejected${scoreText}${suggestion}`);
            }
          }
        } catch (err) {
          setErrorMessage(err instanceof VoiceProcessingError ? err.message : "Internal system analysis failed.");
          setStatus('error');
        }
      };

      await new Promise(r => setTimeout(r, 200));

      mediaRecorderRef.current.start();
      setStatus('recording');
      setCountdown(RECORDING_DURATION_MS / 1000);

      countdownIntervalRef.current = window.setInterval(() => setCountdown(p => (p > 1 ? p - 1 : 0)), 1000);
      recordingTimerRef.current = window.setTimeout(() => stopRecording(), RECORDING_DURATION_MS);

    } catch (err: any) {
      console.error("Biometric Access Error:", err);
      let msg = "Microphone initialization failed.";
      if (err.name === 'NotAllowedError') msg = "Access Denied: Microphone permission was blocked. Reset permissions via the browser's address bar settings.";
      else if (err.name === 'NotFoundError') msg = "Hardware Not Found: Ensure a microphone is connected and enabled.";
      setErrorMessage(msg);
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') mediaRecorderRef.current.stop();
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      mediaRecorderRef.current?.stream.getTracks().forEach(t => t.stop());
    };
  }, []);

  const getMicButtonClasses = () => {
    let base = "w-40 h-40 rounded-full flex items-center justify-center transition-all duration-700 relative group ";
    if (status === 'idle') return base + "bg-blue-600 hover:bg-blue-500 hover:scale-105 shadow-[0_0_50px_rgba(37,99,235,0.4)]";
    base += "cursor-not-allowed scale-90 ";
    if (status === 'recording') base += "bg-red-600 shadow-[0_0_60px_rgba(220,38,38,0.5)]";
    else if (status === 'processing' || status === 'error') base += "bg-gray-800 opacity-20";
    return base;
  };

  return (
    <div className="fixed inset-0 bg-gray-950/95 z-50 flex items-center justify-center p-4 backdrop-blur-2xl transition-all duration-500">
      <div className="bg-gray-900 border border-white/10 rounded-[3rem] shadow-[0_0_100px_rgba(37,99,235,0.15)] w-full max-w-lg p-12 relative ring-1 ring-white/10 overflow-hidden text-center">

        <button onClick={onClose} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors z-20">
            <XMarkIcon className="h-7 w-7" />
        </button>

        <div className="space-y-10 relative z-10">
            <div className="space-y-2">
                <h2 className="text-2xl font-black text-white tracking-tight uppercase italic">{title}</h2>
                <div className="h-1 w-24 bg-blue-600 mx-auto rounded-full"></div>
            </div>

            <div className="bg-gray-800/40 p-8 rounded-3xl border border-white/5 space-y-4">
                <p className="text-xs font-bold text-blue-400 uppercase tracking-widest">Speak the following phrase clearly:</p>
                <h3 className="text-xl md:text-2xl font-bold text-white leading-tight">
                    "{requiredPhrase}"
                </h3>
            </div>

            <div className="flex flex-col items-center justify-center space-y-6">
                 <button onClick={startRecording} disabled={status !== 'idle'} className={getMicButtonClasses()}>
                    {status === 'recording' ? (
                        <div className="flex flex-col items-center">
                            <div className="absolute inset-0 border-[12px] border-white/10 rounded-full animate-ping"></div>
                            <span className="text-white font-black text-2xl">{countdown}s</span>
                        </div>
                    ) : (
                        <MicIcon className={`h-16 w-16 text-white transition-transform ${status === 'recording' ? 'scale-110' : 'group-hover:scale-110'}`} />
                    )}
                </button>

                <div className="h-12 flex flex-col items-center justify-center">
                    {status === 'recording' && (
                        <div className="flex items-center space-x-3 text-red-500">
                             <div className="flex space-x-1">
                                {[...Array(3)].map((_, i) => (
                                    <div key={i} className="w-1 bg-red-500 rounded-full animate-pulse" style={{height: `${12 + (i*4)}px`, animationDelay: `${i*0.1}s`}}></div>
                                ))}
                             </div>
                             <span className="font-bold uppercase tracking-widest text-sm">System Listening...</span>
                        </div>
                    )}
                    {status === 'processing' && (
                        <div className="flex flex-col items-center text-blue-400">
                            <SparklesIcon className="h-8 w-8 mb-2 animate-spin" />
                            <span className="text-xs font-bold uppercase tracking-tighter">Analyzing Biometric Matrix</span>
                        </div>
                    )}
                    {status === 'error' && (
                        <div className="px-6">
                            <p className="text-xs text-red-400 leading-relaxed font-semibold italic">{errorMessage}</p>
                        </div>
                    )}
                    {status === 'idle' && (
                        <p className="text-sm text-gray-400 font-medium">Click the microphone to start capture</p>
                    )}
                </div>
            </div>

             {status === 'error' && (
                <button onClick={() => setStatus('idle')} className="bg-white/5 hover:bg-white/10 text-white px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all border border-white/10">
                    Retry Hardware Initialization
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

export default AuthModal;

