                            <div className="absolute inset-0 border-[12px] border-white/10 rounded-full animate-ping"></div>
                            <span className="text-white font-black text-2xl">{countdown}s</span>
                        </div>
                    ) : (
                        <MicIcon className={`h-16 w-16 text-white transition-transform group-hover:scale-110`} />
                    )}
                </button>

