};

import React, { useState, useEffect, useRef } from 'react';
import { AuthAction, User } from '../types';
import { MicIcon } from './icons/MicIcon';
import { XMarkIcon } from './icons/XMarkIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { generateVoiceprint, compareVoiceprints, getVoiceSimilarityScore, SIMILARITY_THRESHOLD, VoiceProcessingError } from '../utils/audioProcessor';

interface AuthModalProps {
  action: AuthAction;
  onClose: () => void;
  onSuccess: (result?: any) => void;
  onFailure: (reason: string) => void;
}

const RECORDING_DURATION_MS = 5000; 

const AuthModal: React.FC<AuthModalProps> = ({ action, onClose, onSuccess, onFailure }) => {
  const [status, setStatus] = useState<'idle' | 'recording' | 'processing' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [countdown, setCountdown] = useState(RECORDING_DURATION_MS / 1000);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number | null>(null);
  const countdownIntervalRef = useRef<number | null>(null);

  const title = action.type === 'enroll' ? 'Voice Enrollment' : 'Biometric Security Check';
  const requiredPhrase = "Secure my data with the sound of my voice";

  const clearTimers = () => {
    if (recordingTimerRef.current) clearTimeout(recordingTimerRef.current);
    if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
  };

  const startRecording = async () => {
    if (status !== 'idle') return;

    setErrorMessage("");
    audioChunksRef.current = [];

    if (!window.isSecureContext) {
      setErrorMessage("System Restriction: Biometric hardware requires a secure connection (HTTPS or Localhost) to operate.");
      setStatus('error');
      return;
    }

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Biometric API initialization failed. Hardware not detected.");
      }

      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: { 
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true
        }
      });

      const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : '';
      mediaRecorderRef.current = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);

      mediaRecorderRef.current.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      mediaRecorderRef.current.onstop = async () => {
        setStatus('processing');
        stream.getTracks().forEach(t => t.stop());

        if (audioChunksRef.current.length === 0) {
          setErrorMessage("Hardware Error: No data captured. Check your mic.");
          setStatus('error');
          return;
        }

        try {
          const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });
          const currentVoiceprint = await generateVoiceprint(audioBlob);

          if (action.type === 'enroll') {
            onSuccess(currentVoiceprint);
          } else if (action.type === 'verify' || action.type === 'identify') {
            const usersToSearch = action.type === 'verify' ? [action.user] : action.users;
            let bestMatch: User | null = null;
            let maxScore = -1;

            for (const user of usersToSearch) {
              if (user.voiceprint) {
                const score = getVoiceSimilarityScore(currentVoiceprint, user.voiceprint);
                if (score > maxScore) {
                  maxScore = score;
                  bestMatch = user;
                }
              }
            }

            if (bestMatch && maxScore >= SIMILARITY_THRESHOLD) {
              onSuccess(action.type === 'identify' ? { user: bestMatch, voiceprint: currentVoiceprint } : undefined);
            } else {
              const confidence = maxScore > 0 ? (maxScore * 100).toFixed(1) : "0";
              const suggestion = maxScore > 0.60 ? ". Almost there! Try to use the exact same tone as your enrollment." : ". Profile mismatch detected.";
              onFailure(`Biometric Identity Rejected (Score: ${confidence}% / Required: ${(SIMILARITY_THRESHOLD * 100).toFixed(0)}%)${suggestion}`);
            }
          }
        } catch (err) {
          setErrorMessage(err instanceof VoiceProcessingError ? err.message : "Internal analysis failed.");
          setStatus('error');
        }
      };

      await new Promise(r => setTimeout(r, 200));

      mediaRecorderRef.current.start();
      setStatus('recording');
      setCountdown(RECORDING_DURATION_MS / 1000);

      countdownIntervalRef.current = window.setInterval(() => setCountdown(p => (p > 1 ? p - 1 : 0)), 1000);
      recordingTimerRef.current = window.setTimeout(() => stopRecording(), RECORDING_DURATION_MS);

    } catch (err: any) {
      console.error("Biometric Access Error:", err);
      let msg = "Microphone initialization failed.";
      if (err.name === 'NotAllowedError') msg = "Access Denied: Microphone permission was blocked. Check browser settings.";
      else if (err.name === 'NotFoundError') msg = "Hardware Not Found: Ensure a microphone is connected.";
      setErrorMessage(msg);
      setStatus('error');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') mediaRecorderRef.current.stop();
    clearTimers();
  };

  useEffect(() => {
    return () => {
      clearTimers();
      mediaRecorderRef.current?.stream.getTracks().forEach(t => t.stop());
    };
  }, []);

  const getMicButtonClasses = () => {
    let base = "w-40 h-40 rounded-full flex items-center justify-center transition-all duration-700 relative group ";
    if (status === 'idle') return base + "bg-blue-600 hover:bg-blue-500 hover:scale-105 shadow-[0_0_50px_rgba(37,99,235,0.4)]";
    base += "cursor-not-allowed scale-90 ";
    if (status === 'recording') base += "bg-red-600 shadow-[0_0_60px_rgba(220,38,38,0.5)]";
    else if (status === 'processing' || status === 'error') base += "bg-gray-800 opacity-20";
    return base;
  };

  return (
    <div className="fixed inset-0 bg-gray-950/95 z-50 flex items-center justify-center p-4 backdrop-blur-2xl transition-all duration-500">
      <div className="bg-gray-900 border border-white/10 rounded-[3rem] shadow-[0_0_100px_rgba(37,99,235,0.15)] w-full max-w-lg p-12 relative ring-1 ring-white/10 overflow-hidden text-center">

        <button onClick={onClose} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors z-20">
            <XMarkIcon className="h-7 w-7" />
        </button>

        <div className="space-y-10 relative z-10">
            <div className="space-y-2">
                <h2 className="text-2xl font-black text-white tracking-tight uppercase italic">{title}</h2>
                <div className="h-1 w-24 bg-blue-600 mx-auto rounded-full"></div>
            </div>

            <div className="bg-gray-800/40 p-8 rounded-3xl border border-white/5 space-y-4">
                <p className="text-xs font-bold text-blue-400 uppercase tracking-widest">Speak the following phrase clearly:</p>
                <h3 className="text-xl md:text-2xl font-bold text-white leading-tight">
                    "{requiredPhrase}"
                </h3>
            </div>

            <div className="flex flex-col items-center justify-center space-y-6">
                 <button onClick={startRecording} disabled={status !== 'idle'} className={getMicButtonClasses()}>
                    {status === 'recording' ? (
                        <div className="flex flex-col items-center">
                            <div className="absolute inset-0 border-[12px] border-white/10 rounded-full animate-ping"></div>
                            <span className="text-white font-black text-2xl">{countdown}s</span>
                        </div>
                    ) : (
                        <MicIcon className={`h-16 w-16 text-white transition-transform group-hover:scale-110`} />
                    )}
                </button>

                <div className="h-12 flex flex-col items-center justify-center">
                    {status === 'recording' && (
                        <div className="flex items-center space-x-3 text-red-500">
                             <div className="flex space-x-1">
                                {[...Array(3)].map((_, i) => (
                                    <div key={i} className="w-1 bg-red-500 rounded-full animate-pulse" style={{height: `${12 + (i*4)}px`, animationDelay: `${i*0.1}s`}}></div>
                                ))}
                             </div>
                             <span className="font-bold uppercase tracking-widest text-sm">System Listening...</span>
                        </div>
                    )}
                    {status === 'processing' && (
                        <div className="flex flex-col items-center text-blue-400">
                            <SparklesIcon className="h-8 w-8 mb-2 animate-spin" />
                            <span className="text-xs font-bold uppercase tracking-tighter">Analyzing Biometric Matrix</span>
                        </div>
                    )}
                    {status === 'error' && (
                        <div className="px-6">
                            <p className="text-xs text-red-400 leading-relaxed font-semibold italic">{errorMessage}</p>
                        </div>
                    )}
                    {status === 'idle' && (
                        <p className="text-sm text-gray-400 font-medium">Click the microphone to start capture</p>
                    )}
                </div>
            </div>

             {status === 'error' && (
                <button onClick={() => setStatus('idle')} className="bg-white/5 hover:bg-white/10 text-white px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all border border-white/10">
                    Retry Hardware Initialization
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

export default AuthModal;

